from flask import Flask, request, jsonify
from prometheus_client import Counter, Histogram, generate_latest, CONTENT_TYPE_LATEST

app = Flask(__name__)

# Define Prometheus metric counters
REQUEST_COUNT = Counter('request_count', 'App Request Count',
                        ['method', 'endpoint', 'http_status', 'user_id', 'api_key'])
REQUEST_LATENCY = Histogram('request_latency_seconds', 'Request latency',
                            ['endpoint'])

@app.before_request
def start_timer():
    request.start_time = REQUEST_LATENCY.labels(endpoint=request.path).time()

@app.after_request
def stop_timer(response):
    resp_time = request.start_time()
    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=request.path,
        http_status=response.status_code,
        user_id=request.headers.get('X-User-ID', 'unknown'),
        api_key=request.headers.get('X-API-Key', 'unknown')
    ).inc()
    return response

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

@app.route('/api', methods=['GET', 'POST'])
def api():
    request_data = request.json
    response = {
        "message": "API processed",
        "data": request_data
    }
    return jsonify(response)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)